const rows = $input.all().map(i => i.json);

// Mes anterior
const now = new Date();
const firstOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const monthName = firstOfLastMonth.toLocaleString('es-GT', { month: 'long', year: 'numeric' });

// Filtrar por check_in en el mes anterior
const monthRows = rows.filter(r => {
  if (!r.check_in) return false;
  const d = new Date(r.check_in);
  return d >= firstOfLastMonth && d < firstOfMonth;
});

const PRICES = { SVM: 950, SFM: 1450, SP: 2200 };
const ROOM_NAMES = { SVM: 'Suite Vista Mar', SFM: 'Suite Frente al Mar', SP: 'Suite Presidencial' };

let revenue = 0;
const byRoom = { SVM: { count: 0, nights: 0 }, SFM: { count: 0, nights: 0 }, SP: { count: 0, nights: 0 } };

const confirmed = monthRows.filter(r => r.status === 'confirmed' || r.status === 'modified');
const cancelled = monthRows.filter(r => r.status === 'cancelled');

confirmed.forEach(r => {
  const nights = Math.max(1, Math.round((new Date(r.check_out) - new Date(r.check_in)) / 86400000));
  revenue += (PRICES[r.room_type] || 0) * nights;
  if (byRoom[r.room_type]) {
    byRoom[r.room_type].count++;
    byRoom[r.room_type].nights += nights;
  }
});

const roomRows = Object.entries(byRoom)
  .map(([k, v]) => `<tr><td style='padding:10px;border:1px solid #e2e8f0'>${ROOM_NAMES[k]}</td><td style='padding:10px;border:1px solid #e2e8f0;text-align:center'>${v.count}</td><td style='padding:10px;border:1px solid #e2e8f0;text-align:center'>${v.nights}</td><td style='padding:10px;border:1px solid #e2e8f0;text-align:right'>Q${(PRICES[k] * v.nights).toLocaleString()}</td></tr>`)
  .join('');

const html = `<!DOCTYPE html><html><body style='font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px'>
<div style='background:linear-gradient(135deg,#1e3a5f,#0891b2);padding:30px;border-radius:12px 12px 0 0;text-align:center'>
<h1 style='color:white;margin:0'>🌊 Azul Horizonte</h1>
<p style='color:#bae6fd;margin:8px 0 0'>Reporte de Reservaciones — ${monthName}</p>
</div>
<div style='background:white;padding:30px;border:1px solid #e2e8f0;border-radius:0 0 12px 12px'>
<h2 style='color:#1e293b'>Resumen del mes</h2>
<div style='display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin:20px 0'>
<div style='background:#f0f9ff;border-radius:8px;padding:16px;text-align:center'>
<p style='font-size:32px;font-weight:bold;color:#0891b2;margin:0'>${confirmed.length}</p>
<p style='color:#64748b;font-size:14px;margin:4px 0'>Reservaciones activas</p>
</div>
<div style='background:#fef3c7;border-radius:8px;padding:16px;text-align:center'>
<p style='font-size:32px;font-weight:bold;color:#d97706;margin:0'>${cancelled.length}</p>
<p style='color:#64748b;font-size:14px;margin:4px 0'>Cancelaciones</p>
</div>
<div style='background:#f0fdf4;border-radius:8px;padding:16px;text-align:center'>
<p style='font-size:32px;font-weight:bold;color:#16a34a;margin:0'>Q${revenue.toLocaleString()}</p>
<p style='color:#64748b;font-size:14px;margin:4px 0'>Ingresos estimados</p>
</div>
</div>
<h3 style='color:#1e293b'>Por tipo de habitación</h3>
<table style='width:100%;border-collapse:collapse'>
<thead><tr style='background:#f8fafc'>
<th style='padding:10px;border:1px solid #e2e8f0;text-align:left'>Habitación</th>
<th style='padding:10px;border:1px solid #e2e8f0'>Reservas</th>
<th style='padding:10px;border:1px solid #e2e8f0'>Noches</th>
<th style='padding:10px;border:1px solid #e2e8f0;text-align:right'>Ingreso</th>
</tr></thead>
<tbody>${roomRows}</tbody>
</table>
<p style='color:#94a3b8;font-size:12px;margin-top:24px'>Reporte generado automáticamente por n8n · ${new Date().toLocaleDateString('es-GT')}</p>
</div></body></html>`;

return [{ json: { html, monthName, total: monthRows.length, confirmed: confirmed.length, cancelled: cancelled.length, revenue } }];
